#include<bits/stdc++.h>
using namespace std;
int n,m;
char a[201][201];
int dx[] = {1, 0, -1, 0};
int dy[] = {0, 1, 0, -1};
queue<int> x;
queue<int> y;
bool dfs(int x,int y) {
	if(x==m&&y==n){
		return true;
	}
	a[y][x]='#';
	for(int i=0;i<4;i++){
		int mx=x+dx[i];
		int my=y+dy[i];
		if(mx>0&&my>0&&mx<=m&&my<=n){
			if(a[my][mx]=='.'){

				if(dfs(mx,my)){
					return true;
				}
			}
		}
	}
	return false;
}
//bool bfs() {}
int main() {
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cin>>a[i][j];
		}
	}
	if(dfs(1,1)){
		cout<<"Yes";
	}else{
		cout<<"No";
	}
	return 0;
}
